import React, { useState } from 'react';
import { Reveal } from "../components/AboutUs/Reveal";
import SideNav from "../components/AboutUs/SideNav";
import MobileTopNav from "../components/AboutUs/MobileTopNav";

const EquipoPage = () => {
  const [activeCategory, setActiveCategory] = useState('delegacion');
  
  const sections = [
    { id: 'delegacion', label: 'Delegación' },
    { id: 'backend', label: 'Backend' },
    { id: 'frontend', label: 'Frontend' },
    { id: 'basedatos', label: 'Base de Datos' },
    { id: 'dashboard', label: 'Dashboard' }
  ];

  // Datos de ejemplo del equipo
  const teamMembers = {
    delegacion: [
      { id: 1, name: 'Ana Rodríguez', position: 'Project Manager', photo: '👩‍💼' },
      { id: 2, name: 'Carlos Méndez', position: 'Líder de Equipo', photo: '👨‍💼' },
      { id: 3, name: 'María Fernández', position: 'Coordinadora', photo: '👩‍💻' }
    ],
    backend: [
      { id: 1, name: 'Javier López', position: 'Senior Backend Dev', photo: '👨‍💻' },
      { id: 2, name: 'Laura Martínez', position: 'API Specialist', photo: '👩‍🔧' },
      { id: 3, name: 'Diego Ramírez', position: 'DevOps Engineer', photo: '👨‍🔬' }
    ],
    frontend: [
      { id: 1, name: 'Sofía García', position: 'Frontend Lead', photo: '👩‍🎨' },
      { id: 2, name: 'Miguel Ángel Torres', position: 'UI/UX Developer', photo: '👨‍🎨' },
      { id: 3, name: 'Elena Vargas', position: 'React Specialist', photo: '👩‍💻' }
    ],
    basedatos: [
      { id: 1, name: 'Roberto Silva', position: 'Database Architect', photo: '👨‍🔧' },
      { id: 2, name: 'Carolina Ríos', position: 'Data Analyst', photo: '👩‍🔬' },
      { id: 3, name: 'Andrés Castillo', position: 'DB Administrator', photo: '👨‍💼' }
    ],
    dashboard: [
      { id: 1, name: 'Patricia Navarro', position: 'Dashboard Designer', photo: '👩‍💼' },
      { id: 2, name: 'Fernando Jiménez', position: 'Data Visualization', photo: '👨‍🎨' },
      { id: 3, name: 'Gabriela Ortega', position: 'Analytics Specialist', photo: '👩‍🔧' }
    ]
  };

  return (
    <div className="min-h-screen bg-[#F4E9D7]">
      <SideNav sections={sections} />
      <MobileTopNav sections={sections} />

      <div className="md:flex">
        {/* Left reserved column to avoid overlap with fixed sidenav */}
        <aside className="hidden md:block md:w-[18%] lg:w-[17%] xl:w-[15%] shrink-0" aria-hidden />

        {/* Right content column */}
        <div className="md:w-[82%] lg:w-[83%] xl:w-[85%] md:ml-auto">
          {/* Header Section */}
          <section className="relative bg-white scroll-mt-24">
            <div className="container mx-auto px-4 py-16">
              <Reveal>
                <div className="text-center max-w-3xl mx-auto">
                  <h1 className="font-serif text-4xl md:text-5xl text-[#072D42] mb-4">
                    Nuestro <span className="text-[#072D42]">Equipo</span>
                  </h1>
                  <div className="h-1 w-20 bg-[#072D42] mx-auto mb-6"></div>
                  <p className="text-[#072D42]/80 text-lg leading-relaxed">
                    Conoce al talentoso equipo detrás de Orbis Empresarial. 
                    Profesionales comprometidos con la excelencia y la innovación.
                  </p>
                </div>
              </Reveal>
            </div>
          </section>

          {/* Team Sections */}
          {sections.map((section, index) => (
            <section 
              key={section.id} 
              id={section.id} 
              className="relative bg-white scroll-mt-24"
            >
              <div className="container mx-auto px-4 py-16">
                <Reveal delay={index * 100}>
                  <div className="mb-12">
                    <h2 className="font-serif text-3xl text-[#072D42] flex items-center gap-3">
                      {section.label}
                    </h2>
                    <div className="mt-3 mb-8 h-1 w-16 bg-[#072D42]"></div>
                  </div>
                </Reveal>

                <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
                  {teamMembers[section.id].map((member, memberIndex) => (
                    <Reveal key={member.id} delay={(index * 100) + (memberIndex * 50)}>
                      <div className="bg-white rounded-xl p-6 shadow-lg border border-[#072D42]/10 hover:shadow-xl transition-shadow duration-300 group">
                        <div className="flex items-center gap-4 mb-4">
                          <div className="w-16 h-16 bg-[#F4E9D7] rounded-full flex items-center justify-center text-2xl group-hover:bg-[#F29E38] group-hover:text-white transition-colors duration-300">
                            {member.photo}
                          </div>
                          <div>
                            <h3 className="font-semibold text-[#072D42] text-lg">
                              {member.name}
                            </h3>
                            <p className="text-[#072D42]/70 text-sm">
                              {member.position}
                            </p>
                          </div>
                        </div>
                        <div className="h-px bg-[#072D42]/10 my-4"></div>
                        <div className="flex gap-2">
                          <span className="inline-flex items-center rounded-full bg-[#072D42]/10 px-3 py-1 text-xs text-[#072D42]">
                            Experto
                          </span>
                          <span className="inline-flex items-center rounded-full bg-[#F29E38]/10 px-3 py-1 text-xs text-[#072D42]">
                            Comprometido
                          </span>
                        </div>
                      </div>
                    </Reveal>
                  ))}
                </div>
              </div>
            </section>
          ))}

          {/* Call to Action Section */}
          <section className="relative bg-[#072D42] scroll-mt-24">
            <div className="container mx-auto px-4 py-16">
              <Reveal>
                <div className="text-center max-w-2xl mx-auto">
                  <h2 className="font-serif text-3xl text-white mb-4">
                    ¿Quieres unirte a nuestro equipo?
                  </h2>
                  <p className="text-white/80 mb-8">
                    Siempre estamos buscando talento apasionado por la innovación 
                    y la preservación de la memoria empresarial.
                  </p>
                  <button className="bg-[#F29E38] text-white px-8 py-3 rounded-lg font-semibold hover:bg-[#e58c25] transition-colors duration-300">
                    Ver Oportunidades
                  </button>
                </div>
              </Reveal>
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default EquipoPage;
